const input = $json || {};

const buildTypeId = String(
  input.buildTypeId ??
  input.build_type_id ??
  input.buildType ??
  input.btId ??
  ''
).trim();

if (!buildTypeId) {
  throw new Error('Pflichtfeld fehlt: buildTypeId. Beispiel-Input: { "buildTypeId": "demo_alpha_api", "maxTests": 25 }');
}
if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');

const maxTestsRaw = Number(input.maxTests ?? input.max_tests ?? 25);
const maxTests = Number.isFinite(maxTestsRaw) && maxTestsRaw > 0 ? Math.min(Math.floor(maxTestsRaw), 200) : 25;

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    request: {
      buildTypeId,
      maxTests,
      source: 'executeWorkflowTrigger'
    },
    generatedAt: new Date().toISOString()
  }
}];

const input = $json || {};

const buildTypeId = String(
  input.buildTypeId ??
  input.build_type_id ??
  input.buildType ??
  input.btId ??
  $env.TEAMCITY_DEFAULT_FAILED_BUILD_TYPE_ID
).trim();

if (!buildTypeId) {
  throw new Error('Missing buildTypeId. Set TEAMCITY_DEFAULT_FAILED_BUILD_TYPE_ID in .env or pass buildTypeId manually.');
}
if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');

const maxTestsRaw = Number(input.maxTests ?? input.max_tests ?? 25);
const maxTests = Number.isFinite(maxTestsRaw) && maxTestsRaw > 0 ? Math.min(Math.floor(maxTestsRaw), 200) : 25;

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    request: {
      buildTypeId,
      maxTests,
      source: 'manualTrigger'
    },
    generatedAt: new Date().toISOString()
  }
}];

let ctx = {};

try {
  ctx = $items('Build Query Context (Execute)')[0]?.json || {};
} catch (_) {}

if (!ctx || !Object.keys(ctx).length) {
  try {
    ctx = $items('Build Query Context (Manual)')[0]?.json || {};
  } catch (_) {}
}

const src = $json?.body && typeof $json.body === 'object' ? $json.body : ($json || {});
const builds = Array.isArray(src.build) ? src.build : [];
const failedBuild = builds[0] || null;

return [{
  json: {
    ...ctx,
    build: failedBuild
  }
}];

const ctx = $items('Attach Build Details')[0]?.json || {};
const src = $json?.body && typeof $json.body === 'object' ? $json.body : ($json || {});
const testOccurrences = Array.isArray(src.testOccurrence) ? src.testOccurrence : [];

const failedTests = testOccurrences.map((t) => ({
  name: t.name || null,
  status: t.status || null,
  duration: t.duration || null,
  details: t.details || null,
  runOrder: t.runOrder || null
}));

const snapshot = {
  snapshotType: 'teamcity_failed_tests',
  createdAt: new Date().toISOString(),
  requestSource: ctx.request?.source || null,
  buildTypeId: ctx.request?.buildTypeId || null,
  buildId: ctx.build?.id || null,
  maxTestsRequested: ctx.request?.maxTests || null,
  teamcityBaseUrl: ctx.teamcity?.baseUrl || null,
  build: ctx.build || null,
  totalFailedTests: failedTests.length,
  failedTests,
  message: ctx.build
    ? (failedTests.length ? 'Fehlgeschlagene Tests wurden gefunden.' : 'Build gefunden, aber keine fehlgeschlagenen Tests im Resultat.')
    : 'Kein fehlgeschlagener Build fuer diese BuildType-ID gefunden.'
};

return [{ json: snapshot }];

const snapshot = $json;
if (!$env.TEAMCITY_AI_FAILED_TESTS_PATH) throw new Error('Missing env TEAMCITY_AI_FAILED_TESTS_PATH');

const buildTypeIdForFile = String(snapshot.buildTypeId || 'unknown-buildType').trim();
const hasBuildId = !!snapshot.buildId;
const buildIdForFile = hasBuildId ? String(snapshot.buildId) : '';

let filePath = $env.TEAMCITY_AI_FAILED_TESTS_PATH;
filePath = filePath.replace('{buildTypeId}', buildTypeIdForFile);
filePath = filePath.replace('{buildId}', buildIdForFile);

const fileName = hasBuildId
  ? `failed-tests-${buildTypeIdForFile}-build-${buildIdForFile}.json`
  : `failed-tests-${buildTypeIdForFile}.json`;

const jsonText = JSON.stringify(snapshot, null, 2);

return [{
  json: {
    ...snapshot,
    filePath
  },
  binary: {
    data: {
      data: Buffer.from(jsonText, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName
    }
  }
}];

const prepared = $items('Prepare Failed Tests File')[0]?.json || {};

return [{
  json: {
    ok: true,
    message: prepared.message || null,
    buildTypeId: prepared.buildTypeId || null,
    buildId: prepared.buildId || null,
    build: prepared.build || null,
    totalFailedTests: prepared.totalFailedTests || 0,
    failedTests: prepared.failedTests || [],
    filePath: prepared.filePath || null
  }
}];
